use std::collections::HashMap;

fn calculate_total_size(file_sizes: Vec<u64>) -> Result<u64, String> {
    let mut total: u64 = 0;
    
    for &size in &file_sizes {
        total = total.checked_add(size)
            .ok_or_else(|| "Total file size exceeds maximum value".to_string())?;
    }
    
    Ok(total)
}

